final:
module sync_module (
  input clk,
  input data_in,
  input reset_n,
  output reg data_out
);

  reg sync_reg;

  always @(posedge clk or negedge reset_n) begin
    if (~reset_n) begin
      sync_reg <= 1'b0;
      data_out <= 1'b0;
    end else begin
      sync_reg <= data_in;
      data_out <= sync_reg;
    end
  end

endmodule
